import React, { useState } from 'react';
import AppHeader from '../components/AppHeader';
import './NotificationPage.css';

const NAV_ITEMS = [
  { label: 'All Notifications', icon: 'bell', key: 'all' },
  { label: 'RSVPs', icon: 'calendar', key: 'rsvps' },
  { label: 'Photo Uploads', icon: 'camera', key: 'photos' },
  { label: 'Mentions', icon: 'chat', key: 'mentions' },
  { label: 'Settings', icon: 'settings', key: 'settings' },
];

const TABS = ['All', 'Rr VPs', 'Photo Uploads', 'Mentions'];

const NOTIFICATIONS = [
  {
    id: 1,
    type: 'rsvp',
    title: 'New RSVP from Alexander Sterling',
    text: '"Looking forward to the gala! Wouldn\'t miss it for the world. Please note the dietary preference for vegan options."',
    time: '2 mins ago',
    unread: true,
    actions: [
      { label: 'View RSVP', variant: 'primary' },
      { label: 'Reply', variant: 'ghost' },
    ],
  },
  {
    id: 2,
    type: 'photo',
    title: 'Isabella Moore shared 12 new photos',
    text: null,
    time: '45 mins ago',
    unread: false,
    photos: ['/assets/photo1.jpg', '/assets/photo2.jpg'],
    photoCount: 10,
    actions: [
      { label: 'Open Gallery', variant: 'primary' },
    ],
  },
