function NavIcon({ type }) {
  const s = { color: 'currentColor' };
  if (type === 'bell') return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={s}><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>;
  if (type === 'calendar') return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={s}><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>;
  if (type === 'camera') return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={s}><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/></svg>;
  if (type === 'chat') return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={s}><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>;
  if (type === 'settings') return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={s}><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>;
  return null;
}

function NotifIcon({ type }) {
  const col = {
    rsvp: 'var(--primary)', photo: '#6366f1',
    mention: '#8b5cf6', insight: '#7c3aed',
  }[type] || 'var(--primary)';
  return (
    <div className="notif-icon-wrap" style={{ background: col + '18' }}>
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={col} strokeWidth="2">
        {type === 'rsvp' && <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>}
        {type === 'photo' && <><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/></>}
        {type === 'mention' && <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>}
        {type === 'insight' && <><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></>}
      </svg>
    </div>
  );
}

export default function NotificationPage() {
  const [activeNav, setActiveNav] = useState('all');
  const [activeTab, setActiveTab] = useState('All');

  return (
    <div className="app-layout">
      <main className="main-content" style={{ padding: 0 }}>
        <AppHeader
          links={[
            { label: 'Dashboard', href: '/' },
          ]}
        />

        <div className="notif-layout">
          {/* Activity Sidebar */}
          <aside className="notif-sidebar">
            <div className="notif-sidebar-title">Activity Center</div>
            <div className="notif-sidebar-sub">Manage your royal alerts</div>

            {NAV_ITEMS.map(item => (
              <div
                key={item.key}
                className={`notif-nav-item ${activeNav === item.key ? 'active' : ''}`}
                onClick={() => setActiveNav(item.key)}
              >
                <NavIcon type={item.icon} />
                {item.label}
              </div>
            ))}

            <div className="notif-sidebar-bottom">
              <div className="notif-help">
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="12" cy="12" r="10"/>
                  <path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/>
                  <line x1="12" y1="17" x2="12.01" y2="17"/>
                </svg>
                Help Support
              </div>
            </div>
          </aside>

          {/* Main */}
          <div className="notif-main">
            <div className="notif-header-row">
              <div>
                <div className="notif-page-title">Notifications</div>
                <div className="notif-page-sub">Stay updated with your guests and event milestones.</div>
              </div>
              <button className="notif-mark-btn">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <polyline points="20 6 9 17 4 12"/>
                </svg>
                Mark all as read
              </button>
            </div>

            {/* Filter Tabs */}
            <div className="notif-tabs">
              {TABS.map(t => (
                <button
                  key={t}
                  className={`notif-tab ${activeTab === t ? 'active' : ''}`}
                  onClick={() => setActiveTab(t)}
                >
                  {t}
                </button>
              ))}
            </div>

            {/* Cards */}
            <div className="notif-list">
              {NOTIFICATIONS.map(n => (
                <div key={n.id} className={`notif-card ${n.unread ? 'unread' : ''}`}>
                  <div className="notif-card-row">
                    <NotifIcon type={n.type} />
                    <div className="notif-body">
                      <div className="notif-card-title">{n.title}</div>
                      {n.text && <div className="notif-card-text">{n.text}</div>}
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 6, flexShrink: 0 }}>
                      <span className="notif-time">{n.time}</span>
                      {n.unread && (
                        <span>
                          <span className="notif-unread-dot" />
                          <span className="notif-unread-label">UNREAD</span>
                        </span>
                      )}
                    </div>
                  </div>

                  {n.photos && (
                    <div className="notif-photo-strip">
                      {n.photos.map((src, i) => (
                        <div key={i} className="notif-photo-thumb" style={{ background: i === 0 ? '#3b1f5e' : '#2d1a4e' }} />
                      ))}
                      <div className="notif-photo-more">+{n.photoCount}</div>
                    </div>
                  )}

                  {n.actions && (
                    <div className="notif-actions">
                      {n.actions.map((a, i) => (
                        a.variant === 'primary'
                          ? <button key={i} className="notif-btn-primary">{a.label}</button>
                          : <button key={i} className="notif-btn-ghost">{a.label}</button>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="notif-load-more">
              <button className="notif-load-btn">Load older notifications</button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
